+#[must_use]
+pub fn assess_sql_pipeline_optimization(
+    config: &SqlPipelineOptConfig,
+) -> SqlPipelineOptReport {
+    let mut checks = Vec::new();
+
+    let domains_profiled: Vec<String> = OptimizationDomain::ALL
