+
+    SqlPipelineOptReport {
+        schema_version: SQL_PIPELINE_OPT_SCHEMA_VERSION,
+        bead_id: SQL_PIPELINE_OPT_BEAD_ID.to_owned(),
+        verdict,
+        domains_profiled,
+        domains_at_parity,
+        opportunity_score_threshold: config.min_opportunity_score,
+        parity_score,
+        total_checks,
+        checks_at_parity,
+        checks,
+        summary,
+    }
